def encrypt(text, s):
    result = []
    for i in range(len(text)):
        if text[i].isupper():
            # For uppercase letters (A=65 in ASCII)
            ch = chr((ord(text[i]) + s - 65) % 26 + 65)
            result.append(ch)
        else:
            # For lowercase letters (a=97 in ASCII)
            ch = chr((ord(text[i]) + s - 97) % 26 + 97)
            result.append(ch)
    return ''.join(result)

