def find_subsequence_count(S, T):
    m = len(T)
    n = len(S)
    if m > n:
        return 0
    # Create a 2D list initialized with zeros
    mat = [[0 for _ in range(n+1)] for _ in range(m+1)]
    # Initialize first row to 1
    for j in range(n+1):
        mat[0][j] = 1
    # Fill the matrix
    for i in range(1, m+1):
        for j in range(1, n+1):
            if T[i-1] != S[j-1]:
                mat[i][j] = mat[i][j-1]
            else:
                mat[i][j] = mat[i][j-1] + mat[i-1][j-1]
    return mat[m][n]

