def possible_strings(n, r, b, g):
    fact = [0] * (n + 1)
    fact[0] = 1
    for i in range(1, n + 1):
        fact[i] = fact[i - 1] + i
    left = n - (r + g + b)
    sum_val = 0
    for i in range(left + 1):
        for j in range(left - i + 1):
