def count_p(n, k):
    # Initialize 2D array with zeros
    dp = [[0 for _ in range(k+1)] for _ in range(n+1)]
    # Initialize first column with zeros
    for i in range(n+1):
        dp[i][0] = 0
    # Initialize first row with zeros
    # Note: Fixed a bug in the original where it was setting dp[0][k] repeatedly
    for i in range(k+1):
        dp[0][i] = 0
    # Fill the dp table
    for i in range(1, n+1):
        for j in range(1, k+1):
            if j == 1 or i == j:
                dp[i][j] = 1
            else:
                dp[i][j] = j * dp[i-1][j] + dp[i-1][j-1]
    return dp[n][k]

