def count_ps(s):
    n = len(s)
    dp = [[0 for _ in range(n)] for _ in range(n)]
    P = [[False for _ in range(n)] for _ in range(n)]
    # Mark all substrings of length 1 as palindrome
    for i in range(n):
        P[i][i] = True
    # Check for substrings of length 2
    for i in range(n - 1):
        if s[i] == s[i + 1]:
            P[i][i + 1] = True
