def min_pal_partition(string):
    n = len(string)
    # Initialize C and P arrays
    C = [[0 for _ in range(n)] for _ in range(n)]
    P = [[False for _ in range(n)] for _ in range(n)]
    # Initialize base cases
    for i in range(n):
        P[i][i] = True
        C[i][i] = 0
    # Fill the arrays for substrings of length 2 to n
    for L in range(2, n + 1):
        for i in range(n - L + 1):
            j = i + L - 1
            # Check if the substring is a palindrome
            if L == 2:
                P[i][j] = (string[i] == string[j])
            else:
                P[i][j] = (string[i] == string[j]) and P[i + 1][j - 1]
            # If the substring is a palindrome, no cuts needed
            if P[i][j]:
                C[i][j] = 0
            else:
                # Find the minimum number of cuts
                C[i][j] = float('inf')  # Equivalent to Integer.MAX_VALUE
                for k in range(i, j):
