def binary_median(m, r, c):
    max_val = float('-inf')
    min_val = float('inf')
    for i in range(r):
        if m[i][0] < min_val:
            min_val = m[i][0]
        if m[i][c-1] > max_val:
            max_val = m[i][c-1]
    desired = (r * c + 1) // 2
    while min_val < max_val:
        mid = min_val + (max_val - min_val) // 2
        place = 0
        for i in range(r):
            # Find position using binary search
            get = bisect.bisect_left(m[i], mid)
            # If mid is found, skip all occurrences of mid
            if get < len(m[i]) and m[i][get] == mid:
                while get < len(m[i]) and m[i][get] == mid:
                    get += 1
            place += get
        if place < desired:
            min_val = mid + 1
        else:
            max_val = mid
    return min_val

