def xor_zero(s):
    one_count = 0
    zero_count = 0
    n = len(s)
    for i in range(n):
        if s[i] == '1':
            one_count += 1
        else:
            zero_count += 1
    if one_count % 2 == 0:
        return zero_count
    return one_count

